set-variable.value:
@{
            string style = (string)context.Variables["style"];
            int maxLength = (int)context.Variables["maxLength"];

            string styleInstruction;
            if (style == "detailed") {
                styleInstruction = "Provide a comprehensive summary that covers all key points and important details.";
            } else if (style == "bullet_points") {
                styleInstruction = "Provide a summary formatted as bullet points, with each point capturing a key idea.";
            } else {
                styleInstruction = "Provide a brief, concise summary that captures the main points.";
            }

            return string.Format("You are a text summarization assistant. {0} Keep the summary under {1} tokens. Focus on the most important information and maintain clarity.", styleInstruction, maxLength);
        }

inbound.set-body:
@{
            var systemPrompt = (string)context.Variables["systemPrompt"];
            var inputText = (string)context.Variables["inputText"];
            var maxLength = (int)context.Variables["maxLength"];

            return new JObject(
                new JProperty("messages", new JArray(
                    new JObject(
                        new JProperty("role", "system"),
                        new JProperty("content", systemPrompt)
                    ),
                    new JObject(
                        new JProperty("role", "user"),
                        new JProperty("content", inputText)
                    )
                )),
                new JProperty("max_tokens", maxLength),
                new JProperty("temperature", 0.3),
                new JProperty("top_p", 1.0),
                new JProperty("frequency_penalty", 0.0),
                new JProperty("presence_penalty", 0.0)
            ).ToString();
        }

inbound.trace:
@{
                return JsonConvert.SerializeObject(new {
                    EventName = "SummarizeOperationStart",
                    RequestId = context.RequestId,
                    SubscriptionId = context.Subscription?.Id ?? "anonymous",
                    Operation = "summarize",
                    Style = context.Variables["style"],
                    MaxLength = context.Variables["maxLength"],
                    Timestamp = DateTime.UtcNow
                });
            }

set-variable.value:
@{
            int promptTokens = (int)context.Variables["promptTokens"];
            int completionTokens = (int)context.Variables["completionTokens"];
            double inputCost = (promptTokens / 1000000.0) * 2.50;
            double outputCost = (completionTokens / 1000000.0) * 10.00;
            return inputCost + outputCost;
        }

outbound.set-body:
@{
            var summaryText = (string)context.Variables["summaryText"];
            var tokenUsage = (int)context.Variables["tokenUsage"];
            var requestId = (string)context.Variables["requestId"];

            return new JObject(
                new JProperty("summary", summaryText),
                new JProperty("tokens_used", tokenUsage),
                new JProperty("request_id", requestId),
                new JProperty("model", "gpt-4o")
            ).ToString();
        }

outbound.trace:
@{
                return JsonConvert.SerializeObject(new {
                    EventName = "SummarizeOperationComplete",
                    RequestId = context.RequestId,
                    SubscriptionId = context.Subscription?.Id ?? "anonymous",
                    Operation = "summarize",
                    Duration = context.Variables["operationDuration"],
                    TokenUsage = context.Variables["tokenUsage"],
                    PromptTokens = context.Variables["promptTokens"],
                    CompletionTokens = context.Variables["completionTokens"],
                    EstimatedCost = context.Variables["estimatedCost"],
                    ResponseCode = context.Response.StatusCode,
                    Model = "gpt-4o",
                    Timestamp = DateTime.UtcNow
                });
            }

on-error.trace:
@{
                var error = context.LastError;
                return JsonConvert.SerializeObject(new {
                    EventName = "SummarizeOperationError",
                    RequestId = context.RequestId,
                    SubscriptionId = context.Subscription?.Id ?? "anonymous",
                    Operation = "summarize",
                    ErrorSource = error?.Source,
                    ErrorReason = error?.Reason,
                    ErrorMessage = error?.Message,
                    ResponseCode = context.Response?.StatusCode ?? 500,
                    Timestamp = DateTime.UtcNow
                });
            }
